using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ticket_model.zip");

// Train the model at startup
builder.Services.AddHostedService<ModelTrainerService>();

// Thread-safe prediction engine pool
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

string[] categories = ["Billing", "General", "Technical"];

app.MapPost("/api/classify", (TicketRequest request, PredictionEnginePool<TicketInput, TicketPrediction> pool) =>
{
    if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
        return Results.BadRequest(new { error = "Subject and Description are required." });

    if (request.Priority is < 1 or > 3)
        return Results.BadRequest(new { error = "Priority must be between 1 and 3." });

    var input = new TicketInput
    {
        Subject = request.Subject,
        Description = request.Description,
        Priority = request.Priority,
    };

    var prediction = pool.Predict(input);

    var scores = categories
        .Zip(prediction.Score)
        .ToDictionary(pair => pair.First, pair => pair.Second);

    var confidence = prediction.Score.Max();

    return Results.Ok(new TicketResponse(prediction.Category, confidence, scores));
});

app.MapGet("/health", () => Results.Ok(new { status = "healthy" }));

app.Run();

