string[] ResolveLabels()
{
    var mlContext = new MLContext();
    using var stream = File.OpenRead(modelPath);
    var model = mlContext.Model.Load(stream, out var inputSchema);
    var emptyData = mlContext.Data.LoadFromEnumerable(Array.Empty<TicketInput>(), inputSchema);
    var outputSchema = model.GetOutputSchema(emptyData.Schema);
    var labelColumn = outputSchema["Score"];
    var slotNames = new VBuffer<ReadOnlyMemory<char>>();
    labelColumn.GetSlotNames(ref slotNames);
    return slotNames.DenseValues().Select(v => v.ToString()).ToArray();
}

